interface StockItem {
  id: string
  product_name: string
  variant_name: string
  depot_name: string
  lot_number: string | null
  quantity: number
  expiry_date: string | null
  purchase_price: number
}

interface PackagingStockItem {
  id: string
  packaging_name: string
  depot_name: string
  quantity_full: number
  quantity_empty: number
  deposit_amount: number
}

interface Depot {
  id: string
  name: string
  is_main: boolean
}

async function getStockData(companyId: string) {
  try {
    // Get depots
    const depots = await sql`
      SELECT * FROM depots WHERE company_id = ${companyId} ORDER BY is_main DESC, name
    `

    // Get product stock with depot and product info
    const productStock = await sql`
      SELECT 
        s.id,
        p.name as product_name,
        CONCAT(p.name, ' - ', pt.name) as variant_name,
        d.name as depot_name,
        s.lot_number,
        s.quantity,
        s.expiry_date,
        s.purchase_price
      FROM stock s
      JOIN product_variants pv ON s.product_variant_id = pv.id
      JOIN products p ON pv.product_id = p.id
      JOIN packaging_types pt ON pv.packaging_type_id = pt.id
      JOIN depots d ON s.depot_id = d.id
      WHERE p.company_id = ${companyId}
      ORDER BY d.is_main DESC, p.name
    `

    // Get packaging stock
    const packagingStock = await sql`
      SELECT 
        ps.id,
        pt.name as packaging_name,
        d.name as depot_name,
        ps.quantity_full,
        ps.quantity_empty,
        pt.deposit_amount
      FROM packaging_stock ps
      JOIN packaging_types pt ON ps.packaging_type_id = pt.id
      JOIN depots d ON ps.depot_id = d.id
      WHERE pt.company_id = ${companyId}
      ORDER BY d.is_main DESC, pt.name
    `

    // Calculate stats
    const totalProducts = productStock.reduce((acc: number, item: StockItem) => acc + Number(item.quantity), 0)
    const lowStockItems = productStock.filter((item: StockItem) => Number(item.quantity) < 10).length
    const expiringItems = productStock.filter((item: StockItem) => {
      if (!item.expiry_date) return false
      const expiryDate = new Date(item.expiry_date)
      const thirtyDaysFromNow = new Date()
      thirtyDaysFromNow.setDate(thirtyDaysFromNow.getDate() + 30)
      return expiryDate <= thirtyDaysFromNow
    }).length

    return {
      depots: depots as Depot[],
      productStock: productStock as StockItem[],
      packagingStock: packagingStock as PackagingStockItem[],
      stats: {
        totalProducts,
        totalDepots: depots.length,
        lowStockItems,
        expiringItems,
      }
    }
  } catch (error) {
    console.error('Error fetching stock data:', error)
    return {
      depots: [],
      productStock: [],
      packagingStock: [],
      stats: {
        totalProducts: 0,
        totalDepots: 0,
        lowStockItems: 0,
        expiringItems: 0,
      }
    }
  }
}

function formatCurrency(amount: number) {
  return new Intl.NumberFormat('fr-FR', {
    style: 'currency',
    currency: 'XOF',
    minimumFractionDigits: 0,
  }).format(amount)
}

